from dataclasses import dataclass
from datetime import datetime, timezone
from typing import Literal

@dataclass
class IncidentSLATerms:
    acknowledge_within_minutes: int    # Time from breach notification to producer ack
    resolve_within_minutes: int        # Time from breach to data delivery restored
    severity: Literal["P1", "P2", "P3"]
    escalation_path: list[str]         # Ordered list of contacts if unacknowledged

@dataclass
class BreachEvent:
    contract_id: str
    breach_type: str                   # 'latency', 'completeness', 'schema', etc.
    detected_at: datetime
    notification_sent_at: datetime | None
    acknowledged_at: datetime | None
    resolved_at: datetime | None

    def ack_sla_breached(self, sla: IncidentSLATerms) -> bool:
        if not self.notification_sent_at or not self.acknowledged_at:
            return True  # Not yet acknowledged; treat as breached
        elapsed = (self.acknowledged_at - self.notification_sent_at).total_seconds() / 60
        return elapsed > sla.acknowledge_within_minutes

    def resolution_sla_breached(self, sla: IncidentSLATerms) -> bool:
        if not self.resolved_at:
            return True  # Not yet resolved
        elapsed = (self.resolved_at - self.detected_at).total_seconds() / 60
        return elapsed > sla.resolve_within_minutes

    def is_escalation_due(self, sla: IncidentSLATerms) -> bool:
        """True if the breach has not been acknowledged within the ack window."""
        if self.acknowledged_at:
            return False
        if not self.notification_sent_at:
            return False
        elapsed = (
            datetime.now(timezone.utc) - self.notification_sent_at
        ).total_seconds() / 60
        return elapsed > sla.acknowledge_within_minutes
